from typing import Set, List, Optional, Iterable

from geosat.cloud import vobject, pyvoxels, PointCloud

from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

DEFAULT_APPROXIMATE_PARAMS = {
    "vertical_min_meter": 0.8,
    "hanging_min_gap_size": 0.75,
    "hanging_min_dist_to_ground": 0.75,
}


class GroundClassifier(Classifier):
    """This classifier, as the name suggest, classifies ground in a point cloud.

    The classification is made using voxels and is thus fast while still being
    quite accurate.
    """

    def __init__(self, gsd=0.2, stage_name: Optional[str] = None):
        super().__init__(stage_name)
        self.gsd = gsd
        self.approximate_params = DEFAULT_APPROXIMATE_PARAMS
        self.input_class = "unclassified"
        self.output_class = "ground"

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "gsd",
                "Size of voxels used internally, "
                "The bigger the voxels size is, the faster the classification is,"
                "but the less accurate and precise the classification is.",
                type_cast=float,
                required=False,
            )
        ]

    def _cloud_classification(self, cloud, classification_codes):
        in_class_code = classification_codes[self.input_class]
        out_class_code = classification_codes[self.output_class]

        voxels = pyvoxels.voxelize_cloud(
            cloud, self.gsd, mask=cloud.classification == in_class_code
        )

        ground = vobject.approximate_ground_sncf(
            self.gsd,
            voxels,
            cloud,
            # vertical_min_meter=self.approximate_params["vertical_min_meter"],
            # hanging_min_gap_size=self.approximate_params["hanging_min_gap_size"],
            # hanging_min_dist_to_ground=self.approximate_params[
            #     "hanging_min_dist_to_ground"
            # ],
        )
        cloud.classification[ground] = out_class_code

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if cloud:
            self._cloud_classification(cloud, pipeline_metadata.classification_codes)
        return (cloud,)

    def input_classes(self) -> Set[str]:
        return {self.input_class}

    def output_classes(self) -> Set[str]:
        return {self.output_class}
